package com.restaurantcraft.menu; import com.restaurantcraft.registry.ModMenuTypes; import net.minecraft.world.SimpleContainer; import net.minecraft.world.entity.player.*; import net.minecraft.world.inventory.*; import net.minecraft.world.item.ItemStack; public class CustomerOrderMenu extends AbstractContainerMenu { public final int customerId; public final SimpleContainer input=new SimpleContainer(1); public CustomerOrderMenu(int id, Inventory inv, int customerId){super(ModMenuTypes.CUSTOMER_ORDER.get(),id);this.customerId=customerId; addSlot(new Slot(input,0,80,35)); for(int r=0;r<3;r++)for(int c=0;c<9;c++)addSlot(new Slot(inv,c+r*9+9,8+c*18,84+r*18)); for(int c=0;c<9;c++)addSlot(new Slot(inv,c,8+c*18,142));} public boolean stillValid(Player p){return true;} public ItemStack quickMoveStack(Player p,int i){return ItemStack.EMPTY;} public void removed(Player p){super.removed(p); if(!p.level().isClientSide) clearContainer(p,input);} }
